file.content:
.lang-switch {
  display: inline-flex;
  gap: 4px;
  padding: 4px;
  background: var(--bg-card);
  border-radius: 6px;
}

.lang-btn {
  padding: 4px 10px;
  background: transparent;
  border: none;
  color: var(--text-muted);
  font-size: 0.75rem;
  font-weight: 600;
  cursor: pointer;
  border-radius: 4px;
  transition: all 0.2s;
}

.lang-btn:hover {
  color: var(--text-primary);
}

.lang-btn.active {
  background: var(--accent);
  color: white;
}

